#!/usr/bin/env python3
"""
Regression test for issue where dict-like objects with properties couldn't be serialized.
This addresses the issue from https://github.com/marshmallow-code/marshmallow/pull/811
"""

import marshmallow as ma
from marshmallow import utils


class DictWithProperty(dict):
    """A dict-like class with a property."""

    @property
    def prop(self):
        return 12


class DictWithBothKeyAndProperty(dict):
    """A dict-like class with both a key and a property."""

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self['prop'] = 99  # Dict key

    @property
    def prop(self):
        return 12  # Property


class SimpleClassWithProperty:
    """A simple class with a property (this should already work)."""

    @property
    def prop(self):
        return 12


class PropertySchema(ma.Schema):
    prop = ma.fields.Int()


def test_dict_with_property_serialization():
    """Test that dict-like objects with properties can be serialized."""
    obj = DictWithProperty()
    result = PropertySchema().dump(obj)
    assert result == {'prop': 12}


def test_dict_with_both_key_and_property():
    """Test precedence when both dict key and property exist."""
    obj = DictWithBothKeyAndProperty()
    result = PropertySchema().dump(obj)
    # Dict key should take precedence (matching Python's natural behavior)
    assert result == {'prop': 99}


def test_simple_class_with_property():
    """Test that simple classes with properties still work."""
    obj = SimpleClassWithProperty()
    result = PropertySchema().dump(obj)
    assert result == {'prop': 12}


def test_utils_get_value_directly():
    """Test the underlying utils.get_value function directly."""
    obj = DictWithProperty()
    result = utils.get_value(obj, 'prop')
    assert result == 12

    # Test with default
    obj_empty = dict()
    result_default = utils.get_value(obj_empty, 'nonexistent', default='DEFAULT')
    assert result_default == 'DEFAULT'


if __name__ == "__main__":
    test_dict_with_property_serialization()
    test_dict_with_both_key_and_property()
    test_simple_class_with_property()
    test_utils_get_value_directly()
    print("All regression tests passed!")

#!/usr/bin/env python3

import marshmallow as ma
from marshmallow import utils


class BrokenDict:
    """A class that raises TypeError when accessed with []"""
    def __getitem__(self, key):
        raise TypeError("This object doesn't support item access")

    @property
    def prop(self):
        return 42


class AttributeErrorDict(dict):
    """A dict that raises AttributeError when accessing certain keys"""
    def __getitem__(self, key):
        if key == 'broken':
            raise AttributeError("Simulated AttributeError")
        return super().__getitem__(key)

    @property
    def prop(self):
        return 12


class IndexErrorDict(dict):
    """A dict that raises IndexError for certain accesses"""
    def __getitem__(self, key):
        if key == 'indexed_out':
            raise IndexError("Simulated IndexError")
        return super().__getitem__(key)

    @property
    def indexed_out(self):
        return 999


class SchemaForTesting(ma.Schema):
    prop = ma.fields.Int()
    broken = ma.fields.Int()
    indexed_out = ma.fields.Int()


def test_typeerror_fallback():
    """Test that TypeError falls back to getattr"""
    obj = BrokenDict()
    result = utils.get_value(obj, 'prop')
    assert result == 42
    print("✓ TypeError correctly falls back to getattr")


def test_attributeerror_fallback():
    """Test that AttributeError in __getitem__ falls back to getattr"""
    obj = AttributeErrorDict()
    result = utils.get_value(obj, 'prop')
    assert result == 12
    print("✓ AttributeError correctly falls back to getattr")


def test_indexerror_fallback():
    """Test that IndexError falls back to getattr"""
    obj = IndexErrorDict()
    result = utils.get_value(obj, 'indexed_out')
    assert result == 999
    print("✓ IndexError correctly falls back to getattr")


def test_schema_integration():
    """Test that the fix works in full schema context"""
    # Test BrokenDict
    schema = SchemaForTesting()
    broken_result = schema.dump(BrokenDict())
    assert broken_result == {'prop': 42}
    print("✓ BrokenDict works in schema context")

    # Test AttributeErrorDict
    attr_dict = AttributeErrorDict()
    attr_dict['other'] = 55
    attr_result = schema.dump(attr_dict)
    assert attr_result == {'prop': 12}  # Only prop field is in schema
    print("✓ AttributeErrorDict works in schema context")

    # Test IndexErrorDict
    index_dict = IndexErrorDict()
    index_result = schema.dump(index_dict)
    assert index_result == {'indexed_out': 999}
    print("✓ IndexErrorDict works in schema context")


if __name__ == "__main__":
    test_typeerror_fallback()
    test_attributeerror_fallback()
    test_indexerror_fallback()
    test_schema_integration()
    print("All edge case tests passed!")

